public int minDeletions(int[] nums, int[] numsDivide) {
    int res = Integer.MAX_VALUE;
    for (int num : nums) {
        int cnt = 0;
        boolean found = true;
        for (int d : numsDivide) {
            if (d % num != 0) {
                found = false;
                break;
            }
        }
        if (found) {
            for (int n : nums) {
                if (n == num) {
                    cnt++;
                }
            }
            res = Math.min(res, nums.length - cnt);
        }
    }
    return res == Integer.MAX_VALUE ? -1 : res;
}
